added = 0
linkedin_added = 0
for p in NEW_PROFESSORS:
    name_lower = p["name"].lower().strip()
    if name_lower not in existing_names:
        existing.append(p)
        existing_names.add(name_lower)
        added += 1
        if p.get("linkedin_url"):
            linkedin_added += 1

# Also add LinkedIn URLs to existing professors where missing
for p in existing:
    if "linkedin_url" not in p or not p["linkedin_url"]:
        p["linkedin_url"] = li(p["name"], p.get("university", ""))
        linkedin_added += 1

with open(os.path.join(DATA_DIR, "core_professors.json"), "w", encoding="utf-8") as f:
    json.dump(existing, f, indent=2, ensure_ascii=False)

from collections import Counter
countries = Counter(p.get("country","?") for p in existing)
print(f"Added {added} new professors")
print(f"Updated LinkedIn URLs for {linkedin_added} professors (new + existing)")
print(f"Total professors now: {len(existing)}")
print(f"Total countries: {len(countries)}")
for c, n in sorted(countries.items()):
    print(f"  {c}: {n}")
